#include<bits/stdc++.h>
using namespace std;
const int N=2505;
bool flag[N][N],vis[N];
vector<int> mp[N];
int n,m,k,dis[N],cnt;
queue<int> q;
long long s[N],ans;
struct node
{
    long long x,y,tot;
    bool operator<(const node&b)const
    {
        return tot>b.tot;
    }
}a[N*N];
void bfs(int x)
{
    memset(dis,0x3f,sizeof(dis));
    memset(vis,0,sizeof(vis));
    while(!q.empty())
    {
        q.pop();
    }
    dis[x]=0;
    q.push(x);
    vis[x]=1;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        if(dis[t]>k+1)
        {
            continue;
        }
        flag[x][t]=1;
        for(int v:mp[t])
        {
            if(!vis[v])
            {
                vis[v]=1;
                dis[v]=dis[t]+1;
                q.push(v);
            }
        }
    }
}
bool check(int x,int y)
{
    if(!flag[a[x].y][a[y].y]||a[x].x==a[y].y||a[x].y==a[y].x||a[x].x==a[y].x||a[x].y==a[y].y)
    {
        return false;
    }
    return true;
}
int main()
{
    scanf("%d%d%d",&n,&m,&k);
    for(int i=2;i<=n;i++)
    {
        scanf("%lld",&s[i]);
    }
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
    {
        bfs(i);
    }
    for(int i=2;i<=n;i++)
    {
        if(flag[1][i])
        {
            for(int j=2;j<=n;j++)
            {
                if(i!=j&&flag[i][j])
                {
                    a[++cnt]=(node){i,j,s[i]+s[j]};
                }
            }
        }
    }
    sort(a+1,a+1+cnt);
    for(int i=1;i<=cnt;i++)
    {
        for(int j=1;j<=cnt;j++)
        {
            if(a[i].tot+a[j].tot<=ans)
            {
                break;
            }
            if(check(i,j))
            {
                ans=a[i].tot+a[j].tot;
            }
        }
    }
    printf("%lld",ans);
    return 0;
}
